def solve(*args):
    if not args:
        return None

    # Assuming args should contain numeric values for scoring
    scores = []
    for arg in args:
        if isinstance(arg, (int, float)):
            scores.append(arg)
        else:
            return None  # Invalid input

    if not scores:
        return None

    # Calculate the score based on some logic, e.g., average
    total_score = sum(scores)
    average_score = total_score / len(scores)

    return average_score
